import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import WeatherOverlay from "./WeatherOverlay";

export default function WeatherApp() {
  const weatherCondition = "clear";
  const isDaytime = true;

  const cards = [
    { label: "Temperature", value: "36.2°C" },
    { label: "Humidity", value: "70%" },
    { label: "Wind Speed", value: "12 km/h" },
    { label: "UV Index", value: "5 (Moderate)" },
    { label: "Visibility", value: "10 km" },
    { label: "Pressure", value: "1012 hPa" },
  ];

  const forecastData = [
    { day: "Mon", temp: "33°C", condition: "☀️ Sunny" },
    { day: "Tue", temp: "30°C", condition: "🌧 Rain" },
    { day: "Wed", temp: "29°C", condition: "🌥 Cloudy" },
    { day: "Thu", temp: "31°C", condition: "⛈ Thunder" },
    { day: "Fri", temp: "28°C", condition: "🌦 Showers" },
    { day: "Sat", temp: "27°C", condition: "☁️ Overcast" },
    { day: "Sun", temp: "34°C", condition: "☀️ Sunny" },
  ];

  const [currentIndex, setCurrentIndex] = useState(0);
  const [favorites, setFavorites] = useState(["Atlanta"]);
  const [search, setSearch] = useState("");
  const [isMobile, setIsMobile] = useState(window.innerWidth <= 768);

  useEffect(() => {
    const handleResize = () => setIsMobile(window.innerWidth <= 768);
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  const handleCardClick = () => {
    setCurrentIndex((prev) => (prev + 1) % cards.length);
  };

  const handleAddFavorite = () => {
    if (search && !favorites.includes(search)) {
      setFavorites([...favorites, search]);
      setSearch("");
    }
  };

  return (
    <div className="relative flex flex-col items-center justify-start min-h-screen overflow-y-auto bg-white dark:bg-black pt-10">
      <WeatherOverlay weatherCondition={weatherCondition} isDaytime={isDaytime} />

      {/* Search + Favorites */}
      <div className="z-10 w-full max-w-md px-4 mb-4">
        <input
          type="text"
          placeholder="Search for a city"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="w-full px-4 py-2 rounded-xl border border-white/20 bg-black/40 text-white backdrop-blur placeholder-white/60"
        />
        <button
          onClick={handleAddFavorite}
          className="mt-2 w-full py-2 bg-purple-500 text-white rounded-xl hover:bg-purple-600"
        >
          Add to Favorites
        </button>
      </div>

      <div className="flex flex-wrap justify-center gap-2 mb-4 z-10">
        {favorites.map((city, idx) => (
          <button
            key={idx}
            className="px-3 py-1 bg-purple-200/40 rounded-full text-white hover:bg-purple-400 transition"
          >
            {city}
          </button>
        ))}
      </div>

      {/* Header */}
      <div className="text-center z-10">
        <h1 className="text-4xl font-bold text-white drop-shadow-glow">
          Today in <span className="text-purple-400">Atlanta</span>
        </h1>
        <p className="text-lg text-white/70 mt-1 capitalize drop-shadow-glow">
          {weatherCondition}
        </p>
      </div>

      {/* Weather Cards */}
      <div className={`mt-6 z-10 w-full px-6 ${isMobile ? "" : "flex justify-center"}`}>
        {isMobile ? (
          <div className="relative w-[240px] h-[140px] cursor-pointer mx-auto" onClick={handleCardClick}>
            {cards.map((card, index) => (
              <div
                key={index}
                className={`absolute top-0 left-0 w-full h-full transition-all duration-500 ease-in-out ${
                  index === currentIndex
                    ? "z-20 opacity-100 scale-100"
                    : "z-0 opacity-0 scale-95"
                } flex flex-col items-center justify-center bg-black/40 backdrop-blur-xl rounded-2xl shadow-xl ring-1 ring-white/20 border-t border-white/30`}
              >
                <p className="text-sm font-semibold text-white mb-1">{card.label}</p>
                <p className="text-2xl font-bold text-white">{card.value}</p>
              </div>
            ))}
            <div className="absolute bottom-2 left-1/2 transform -translate-x-1/2 flex space-x-1">
              {cards.map((_, idx) => (
                <span
                  key={idx}
                  className={`w-2 h-2 rounded-full ${
                    idx === currentIndex ? "bg-purple-400" : "bg-purple-300 opacity-30"
                  } transition-all duration-300`}
                />
              ))}
            </div>
          </div>
        ) : (
          <div className="grid grid-cols-3 gap-4">
            {cards.map((card, idx) => (
              <div
                key={idx}
                className="w-[120px] h-[120px] flex flex-col items-center justify-center text-center bg-black/40 backdrop-blur-xl rounded-xl shadow-xl ring-1 ring-white/20 border-t border-white/30"
              >
                <p className="text-sm font-semibold text-white mb-1">{card.label}</p>
                <p className="text-xl font-bold text-white">{card.value}</p>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Forecast Cards Section */}
      <div className={`z-10 w-full max-w-5xl ${isMobile ? "pt-4 px-4 space-y-2" : "mt-6 px-6 flex justify-center flex-wrap gap-4"}`}>
        {forecastData.map((day, idx) => (
          <div
            key={idx}
            className={`flex flex-col justify-center items-center text-white backdrop-blur-xl ring-1 ring-white/20 border-t border-white/30 shadow-md rounded-xl px-4 transition duration-300 hover:bg-purple-200/20 hover:scale-[1.01] ${
              isMobile ? "w-full h-[70px] bg-black/30" : "w-[120px] h-[120px] bg-black/40"
            }`}
          >
            <span className="font-semibold text-sm">{day.day}</span>
            <span className="text-xs">{day.condition}</span>
            <span className="font-medium text-sm">{day.temp}</span>
          </div>
        ))}
      </div>

      {/* Bottom Navigation */}
      <nav className="fixed bottom-0 left-0 w-full bg-black/30 backdrop-blur-md border-t border-white/10 z-10">
        <ul className="flex justify-around py-3">
          {[
            { icon: "🌤", label: "Today", path: "/" },
            { icon: "☁️", label: "Forecast", path: "/forecast" },
            { icon: "📡", label: "Radar", path: "/radar" },
            { icon: "💬", label: "Community", path: "/community" },
            { icon: "🤖", label: "Chatbot", path: "/chatbot" },
          ].map((tab, idx) => (
            <li key={idx}>
              <Link
                to={tab.path}
                className="flex flex-col items-center text-white/80 hover:text-white transition"
              >
                <span className="text-lg">{tab.icon}</span>
                <span className="text-xs mt-1 font-medium">{tab.label}</span>
              </Link>
            </li>
          ))}
        </ul>
      </nav>
    </div>
  );
}
